// OAuth 2.0 Implicit Flow Client for SPA

// Configuration
const authConfig = {
  authUrl: 'https://auth.example.com/authorize',
  clientId: 'your-client-id',
  redirectUri: window.location.origin,
  responseType: 'token',
  scope: 'read write',
  state: 'randomStateString' // Use a secure random string generator
};

// Initiate OAuth 2.0 Implicit Flow
function initiateOAuthFlow() {
  const authEndpoint = `${authConfig.authUrl}?response_type=${authConfig.responseType}&client_id=${authConfig.clientId}&redirect_uri=${encodeURIComponent(authConfig.redirectUri)}&scope=${encodeURIComponent(authConfig.scope)}&state=${authConfig.state}`;
  window.location.href = authEndpoint;
}

// Parse Access Token from URL Fragment
function parseAccessTokenFromUrl() {
  const hash = window.location.hash.substring(1);
  const params = new URLSearchParams(hash);
  const accessToken = params.get('access_token');
  const state = params.get('state');

  // Validate state to prevent CSRF attacks
  if (state !== authConfig.state) {
    console.error('Invalid state parameter');
    return null;
  }

  return accessToken;
}

// Store Access Token Securely
function storeAccessToken(accessToken) {
  if (accessToken) {
    sessionStorage.setItem('accessToken', accessToken);
  }
}

// Use Access Token for API Calls
function apiCall(endpoint) {
  const accessToken = sessionStorage.getItem('accessToken');
  if (!accessToken) {
    console.error('No access token available');
    return;
  }

  fetch(endpoint, {
    headers: {
      'Authorization': `Bearer ${accessToken}`
    }
  })
  .then(response => response.json())
  .then(data => console.log(data))
  .catch(error => console.error('API call error:', error));
}

// Check for Access Token on Page Load
window.onload = function() {
  const accessToken = parseAccessTokenFromUrl();
  if (accessToken) {
    storeAccessToken(accessToken);
    // Clean up URL to remove fragment
    window.history.replaceState({}, document.title, window.location.pathname);
  }
};

